@inherits LayoutComponentBase
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_0cfa644632de4f659bbf606db932bcd7.Services.WizardDataStore Store

@* This layout renders statically. It reads the URL to determine the current
   step and checks the singleton store (via the session ID available from
   HttpContext) to know which steps are already completed. *@

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <div class="d-flex align-items-center w-100">
                <strong class="me-3">Application: Step @CurrentStep of 4</strong>
                <div class="progress flex-grow-1" style="height: 8px;">
                    <div class="progress-bar" role="progressbar"
                         style="width: @(CurrentStep * 25)%"></div>
                </div>
            </div>
        </div>

        <nav class="px-4 py-2 d-flex gap-3 border-bottom bg-light">
            @for (int i = 0; i < Steps.Length; i++)
            {
                var step = Steps[i];
                var stepNum = i + 1;
                var isCurrent = stepNum == CurrentStep;
                var isCompleted = IsStepCompleted(stepNum);
                var css = isCurrent ? "fw-bold text-primary"
                        : isCompleted ? "text-success"
                        : "text-muted";

                <a href="@step.Href" class="text-decoration-none @css">
                    @if (isCompleted)
                    {
                        <span>✓</span>
                    }
                    @step.Label
                </a>
            }
        </nav>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private record StepInfo(string Href, string Label);

    private static readonly StepInfo[] Steps =
    [
        new("/apply/personal-info", "1. Personal Info"),
        new("/apply/experience",    "2. Experience"),
        new("/apply/references",    "3. References"),
        new("/apply/review",        "4. Review"),
    ];

    private int CurrentStep => GetCurrentStep();
    private WizardData? _wizardData;

    protected override void OnInitialized()
    {
        var session = HttpContextAccessor.HttpContext?.Session;
        if (session is not null)
        {
            // Touch the session to ensure a session ID cookie is issued.
            session.SetString("_init", "1");
            _wizardData = Store.GetOrCreate(session.Id);
        }
    }

    private int GetCurrentStep()
    {
        var path = HttpContextAccessor.HttpContext?.Request.Path.Value ?? "";
        return path switch
        {
            _ when path.Contains("personal-info") => 1,
            _ when path.Contains("experience")    => 2,
            _ when path.Contains("references")    => 3,
            _ when path.Contains("review")        => 4,
            _ => 1,
        };
    }

    private bool IsStepCompleted(int step)
    {
        if (_wizardData is null) return false;
        return step switch
        {
            1 => _wizardData.HasPersonalInfo,
            2 => _wizardData.HasExperience,
            3 => _wizardData.HasReferences,
            _ => false,
        };
    }
}

using Microsoft.AspNetCore.Components;
using sv_0cfa644632de4f659bbf606db932bcd7.Services;

namespace sv_0cfa644632de4f659bbf606db932bcd7.Components.Pages.Apply;

/// <summary>
/// Base class for wizard step pages. Bridges the session ID from the static
/// prerender phase (where HttpContext is available) to the interactive circuit
/// (where it is not) using PersistentComponentState.
/// </summary>
public abstract class WizardStepBase : ComponentBase, IDisposable
{
    [Inject] private IHttpContextAccessor HttpContextAccessor { get; set; } = default!;
    [Inject] private PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] protected WizardDataStore Store { get; set; } = default!;
    [Inject] protected NavigationManager Nav { get; set; } = default!;

    protected WizardData Wizard { get; private set; } = new();

    private PersistingComponentStateSubscription _subscription;
    private string _sessionId = "";

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(PersistState);

        if (PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
        {
            // Interactive mode — HttpContext is gone, use the persisted ID.
            _sessionId = restored!;
        }
        else
        {
            // Prerender phase — HttpContext is available.
            var session = HttpContextAccessor.HttpContext?.Session;
            if (session is not null)
            {
                session.SetString("_init", "1");
                _sessionId = session.Id;
            }
        }

        Wizard = Store.GetOrCreate(_sessionId);
    }

    private Task PersistState()
    {
        PersistentState.PersistAsJson("wizardSessionId", _sessionId);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

