@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardStepBase

<PageTitle>Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

<EditForm Model="Wizard.Personal" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Wizard.Personal.Name" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="Wizard.Personal.Email" />
    </div>

    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    private void Next()
    {
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardStepBase

<PageTitle>Experience</PageTitle>

<h1>Step 2: Work Experience</h1>

@if (Wizard.Experience.Count > 0)
{
    <table class="table table-sm mb-3">
        <thead>
            <tr><th>Title</th><th>Company</th><th>Years</th><th></th></tr>
        </thead>
        <tbody>
            @foreach (var entry in Wizard.Experience)
            {
                <tr>
                    <td>@entry.JobTitle</td>
                    <td>@entry.Company</td>
                    <td>@entry.Years</td>
                    <td>
                        <button class="btn btn-sm btn-outline-danger"
                                @onclick="() => Wizard.Experience.Remove(entry)">
                            Remove
                        </button>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

<EditForm Model="_newEntry" OnValidSubmit="AddEntry" FormName="add-experience">
    <div class="row g-2 mb-3">
        <div class="col-md-4">
            <InputText class="form-control" placeholder="Job title"
                       @bind-Value="_newEntry.JobTitle" />
        </div>
        <div class="col-md-4">
            <InputText class="form-control" placeholder="Company"
                       @bind-Value="_newEntry.Company" />
        </div>
        <div class="col-md-2">
            <InputText class="form-control" placeholder="Years"
                       @bind-Value="_newEntry.Years" />
        </div>
        <div class="col-md-2">
            <button type="submit" class="btn btn-outline-primary w-100">Add</button>
        </div>
    </div>
</EditForm>

<div class="d-flex gap-2">
    <a href="/apply/personal-info" class="btn btn-secondary">← Back</a>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private ExperienceEntry _newEntry = new();

    private void AddEntry()
    {
        Wizard.Experience.Add(_newEntry);
        _newEntry = new();
    }

    private void Next()
    {
        Nav.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardStepBase

<PageTitle>References</PageTitle>

<h1>Step 3: References</h1>

@if (Wizard.References.Count > 0)
{
    <table class="table table-sm mb-3">
        <thead>
            <tr><th>Name</th><th>Relationship</th><th>Phone</th><th></th></tr>
        </thead>
        <tbody>
            @foreach (var r in Wizard.References)
            {
                <tr>
                    <td>@r.Name</td>
                    <td>@r.Relationship</td>
                    <td>@r.Phone</td>
                    <td>
                        <button class="btn btn-sm btn-outline-danger"
                                @onclick="() => Wizard.References.Remove(r)">
                            Remove
                        </button>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

<EditForm Model="_newRef" OnValidSubmit="AddReference" FormName="add-reference">
    <div class="row g-2 mb-3">
        <div class="col-md-4">
            <InputText class="form-control" placeholder="Name"
                       @bind-Value="_newRef.Name" />
        </div>
        <div class="col-md-4">
            <InputText class="form-control" placeholder="Relationship"
                       @bind-Value="_newRef.Relationship" />
        </div>
        <div class="col-md-2">
            <InputText class="form-control" placeholder="Phone"
                       @bind-Value="_newRef.Phone" />
        </div>
        <div class="col-md-2">
            <button type="submit" class="btn btn-outline-primary w-100">Add</button>
        </div>
    </div>
</EditForm>

<div class="d-flex gap-2">
    <a href="/apply/experience" class="btn btn-secondary">← Back</a>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private ReferenceContact _newRef = new();

    private void AddReference()
    {
        Wizard.References.Add(_newRef);
        _newRef = new();
    }

    private void Next()
    {
        Nav.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardStepBase

<PageTitle>Review Application</PageTitle>

<h1>Step 4: Review Your Application</h1>

<div class="card mb-3">
    <div class="card-header">Personal Information</div>
